const payload = $json || {};
const parseArray = (value) => {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') { try { const p = JSON.parse(value); return Array.isArray(p) ? p : []; } catch (_) { return []; } }
  return [];
};
const parseObj = (value) => {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value === 'string') { try { const p = JSON.parse(value); return p && typeof p === 'object' && !Array.isArray(p) ? p : {}; } catch (_) { return {}; } }
  return {};
};
const stats = parseObj(payload.stats);
const auditLogs = parseArray(payload.audit_logs);
const meetingLogs = parseArray(payload.meeting_logs);
const meetings = parseArray(payload.meetings);
const outboxLogs = parseArray(payload.outbox_logs);
const inboxLogs = parseArray(payload.inbox_logs);
const healthSnapshots = parseArray(payload.health_snapshots);
const raidItems = parseArray(payload.raid_items);
const actionItems = parseArray(payload.action_items);
const esc = (v) => String(v ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
const fmt = (v) => v ? new Date(v).toLocaleString('es-EC', { timeZone: 'America/Guayaquil', dateStyle: 'medium', timeStyle: 'short' }) : '-';
const n = (v) => Number(v || 0);
const badge = (status) => {
  const s = String(status || 'unknown').toLowerCase();
  const cls = ['error','failed','dead'].includes(s) ? 'bad' : ['pending','processing','sending','ingested','proposed'].includes(s) ? 'warn' : 'ok';
  return `<span class='badge ${cls}'>${esc(status || 'unknown')}</span>`;
};
const detail = (obj) => `<pre>${esc(JSON.stringify(parseObj(obj), null, 2)).slice(0, 1200)}</pre>`;
const rows = (items, mapper, empty) => items.length ? items.map(mapper).join('') : `<tr><td colspan='5' class='empty'>${esc(empty)}</td></tr>`;
const html = `<!doctype html><html lang='es'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>PetSafe PM Logs</title><style>
:root{--bg:#0d1421;--panel:#141f31;--line:rgba(148,163,184,.18);--text:#eef4ff;--muted:#94a3b8;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444;--accent:#60a5fa}*{box-sizing:border-box}body{margin:0;font-family:Inter,system-ui,Arial,sans-serif;background:linear-gradient(135deg,#0d1421,#111827 60%,#18243a);color:var(--text)}.shell{width:min(1220px,calc(100% - 28px));margin:24px auto 48px}.hero{border:1px solid var(--line);border-radius:24px;background:rgba(20,31,49,.86);padding:26px;box-shadow:0 24px 70px rgba(0,0,0,.35)}h1{margin:0 0 8px;font-size:clamp(2rem,4vw,3rem)}p{color:var(--muted);line-height:1.55}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:20px}.stat{border:1px solid var(--line);border-radius:18px;padding:16px;background:rgba(255,255,255,.035)}.stat span{display:block;color:var(--muted);font-size:.75rem;text-transform:uppercase;letter-spacing:.08em}.stat strong{font-size:1.8rem}.grid{display:grid;grid-template-columns:1fr;gap:18px;margin-top:20px}.panel{border:1px solid var(--line);border-radius:22px;background:rgba(20,31,49,.82);overflow:hidden}.panel-head{display:flex;justify-content:space-between;gap:12px;align-items:center;padding:16px 18px;border-bottom:1px solid var(--line)}h2{margin:0;font-size:1rem}.toolbar input{background:#0b1220;border:1px solid var(--line);border-radius:12px;color:var(--text);padding:10px 12px;min-width:260px}table{width:100%;border-collapse:collapse;font-size:.86rem}th,td{padding:12px 14px;border-bottom:1px solid rgba(148,163,184,.1);vertical-align:top;text-align:left}th{color:var(--muted);font-size:.72rem;text-transform:uppercase;letter-spacing:.07em}.badge{display:inline-flex;border-radius:999px;padding:5px 9px;font-size:.72rem;font-weight:800}.badge.ok{background:rgba(34,197,94,.14);color:#bbf7d0}.badge.warn{background:rgba(245,158,11,.14);color:#fde68a}.badge.bad{background:rgba(239,68,68,.14);color:#fecaca}code,pre{font-family:ui-monospace,SFMono-Regular,Menlo,monospace}pre{white-space:pre-wrap;max-width:460px;max-height:180px;overflow:auto;background:#0b1220;border:1px solid var(--line);border-radius:12px;padding:10px;color:#cbd5e1}.empty{color:var(--muted);text-align:center}.hide{display:none}@media(max-width:760px){.stats{grid-template-columns:1fr}.toolbar input{min-width:0;width:100%}th:nth-child(4),td:nth-child(4){display:none}}</style></head><body><div class='shell'>
<section class='hero'><h1>PetSafe PM Logs Hub</h1><p>Vista de auditoria para flujos n8n, reuniones PMO, outbox Discord e inbox de eventos. Sirve para revisar que hizo el bot, cuando lo hizo y donde fallo.</p><div class='stats'>
<div class='stat'><span>Runs 24h</span><strong>${n(stats.audit_total_24h)}</strong><p>${n(stats.audit_errors_24h)} errores</p></div>
<div class='stat'><span>Outbox</span><strong>${n(stats.outbox_pending)}</strong><p>${n(stats.outbox_dead)} muertos</p></div>
<div class='stat'><span>Reuniones abiertas</span><strong>${n(stats.meetings_open)}</strong><p>${n(stats.inbox_failed)} eventos fallidos</p></div>
</div></section>
<section class='grid'>
<div class='panel'><div class='panel-head'><h2>PMO health</h2></div><table><thead><tr><th>Estado</th><th>Score</th><th>Fecha</th><th>Resumen</th><th>Recomendaciones</th></tr></thead><tbody>${rows(healthSnapshots,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.health_status)}</td><td><strong>${esc(r.health_score)}/100</strong></td><td>${esc(fmt(r.created_at))}</td><td>${esc(r.summary||'-')}</td><td>${detail(r.recommendations)}</td></tr>`,'Sin snapshots PMO.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>RAID abierto</h2></div><table><thead><tr><th>Tipo</th><th>Titulo</th><th>Severidad</th><th>Owner</th><th>Due</th></tr></thead><tbody>${rows(raidItems,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${esc(r.item_type)}</td><td><strong>${esc(r.title)}</strong></td><td>${badge(r.severity)}</td><td>${esc(r.owner||'-')}</td><td>${esc(fmt(r.due_date))}</td></tr>`,'Sin RAID abierto.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Acciones PMO abiertas</h2></div><table><thead><tr><th>Prioridad</th><th>Accion</th><th>Owner</th><th>Estado</th><th>Due</th></tr></thead><tbody>${rows(actionItems,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.priority)}</td><td><strong>${esc(r.title)}</strong></td><td>${esc(r.owner||'-')}</td><td>${esc(r.status)}</td><td>${esc(fmt(r.due_date))}</td></tr>`,'Sin acciones PMO abiertas.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Audit logs n8n</h2><div class='toolbar'><input placeholder='Filtrar...' oninput='filterRows(this.value)'></div></div><table><thead><tr><th>Estado</th><th>Workflow</th><th>Fecha</th><th>Correlation</th><th>Detalle</th></tr></thead><tbody>${rows(auditLogs,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.status)}</td><td><strong>${esc(r.workflow_name||r.workflow_id)}</strong></td><td>${esc(fmt(r.started_at))}</td><td><code>${esc(r.correlation_id||'-')}</code></td><td>${detail(r.error_details || r.metrics)}</td></tr>`,'Sin auditoria registrada.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Reuniones PMO</h2></div><table><thead><tr><th>Estado</th><th>Titulo</th><th>Fecha</th><th>Solicitado por</th><th>URL</th></tr></thead><tbody>${rows(meetings,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.status)}</td><td><strong>${esc(r.title)}</strong><br><small>${esc(r.priority||'')}</small></td><td>${esc(fmt(r.scheduled_for||r.created_at))}</td><td>${esc(r.requested_by||'-')}</td><td>${r.calendar_url?`<a href='${esc(r.calendar_url)}'>Abrir</a>`:'-'}</td></tr>`,'Sin reuniones registradas.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Meeting logs</h2></div><table><thead><tr><th>Accion</th><th>Actor</th><th>Fecha</th><th>Correlation</th><th>Detalle</th></tr></thead><tbody>${rows(meetingLogs,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${esc(r.action)}</td><td>${esc(r.actor||'-')}</td><td>${esc(fmt(r.created_at))}</td><td><code>${esc(r.correlation_id||'-')}</code></td><td>${detail(r.details)}</td></tr>`,'Sin logs de reuniones.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Outbox Discord</h2></div><table><thead><tr><th>Estado</th><th>Accion</th><th>Fecha</th><th>Retries</th><th>Error</th></tr></thead><tbody>${rows(outboxLogs,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.status)}</td><td>${esc(r.target)} / ${esc(r.action)}</td><td>${esc(fmt(r.scheduled_at))}</td><td>${esc(r.retry_count)}</td><td>${esc(r.last_error||'-')}</td></tr>`,'Outbox limpio.')}</tbody></table></div>
<div class='panel'><div class='panel-head'><h2>Inbox eventos</h2></div><table><thead><tr><th>Estado</th><th>Evento</th><th>Fecha</th><th>Retries</th><th>Error</th></tr></thead><tbody>${rows(inboxLogs,(r)=>`<tr data-search='${esc(JSON.stringify(r).toLowerCase())}'><td>${badge(r.processing_status)}</td><td>${esc(r.source)} / ${esc(r.event_type)}</td><td>${esc(fmt(r.received_at))}</td><td>${esc(r.retry_count)}</td><td>${esc(r.last_error||'-')}</td></tr>`,'Inbox sin pendientes relevantes.')}</tbody></table></div>
</section></div><script>function filterRows(q){q=(q||'').toLowerCase();document.querySelectorAll('tr[data-search]').forEach((r)=>{r.classList.toggle('hide',q&&!r.dataset.search.includes(q));});}</script></body></html>`;
return [{ json: { html } }];
